wire [1:0] pos_temp;
assign pos_temp = (in[3]) ? 2'b11 :
                 (in[2]) ? 2'b10 :
                 (in[1]) ? 2'b01 :
                 (in[0]) ? 2'b00 :
                           2'b00 ;

assign pos = (in == 4'b0000) ? 2'b00 : pos_temp;

  always @(*) begin
    if (1'b0) begin
      if (in[0]) begin
        pos_temp <= 2'b00;
      end else if (in[1]) begin
        pos_temp <= 2'b01;
      end else if (in[2]) begin
        pos_temp <= 2'b10;
      end else if (in[3]) begin
        pos_temp <= 2'b11;
      end
    end
  end

endmodule

